realWorldExample.code:
@Component
@Scope("prototype")
class CartCalculator {
    private BigDecimal total = BigDecimal.ZERO;
    void add(BigDecimal amount) { total = total.add(amount); }
    BigDecimal getTotal() { return total; }
}

@Service
class CartService {
    private final ObjectProvider<CartCalculator> calculatorProvider;

    CartService(ObjectProvider<CartCalculator> calculatorProvider) {
        this.calculatorProvider = calculatorProvider;
    }

    BigDecimal calculate(List<BigDecimal> amounts) {
        CartCalculator calculator = calculatorProvider.getObject();
        amounts.forEach(calculator::add);
        return calculator.getTotal();
    }
}

